 1→import React from 'react';
 2→import { RefreshCw, WifiOff, AlertCircle, CheckCircle } from 'lucide-react';
 3→
 4→interface Props {
 5→  pending: number;
 6→  failed: number;
 7→  synced: number;
 8→  isOffline: boolean;
 9→  isSyncing: boolean;
10→  onTap?: () => void;
11→  onRefresh?: () => void;
12→  language: 'en' | 'fr';
13→}
14→
15→const SyncStatusBar: React.FC<Props> = ({
16→  pending,
17→  failed,
18→  synced,
19→  isOffline,
20→  isSyncing,
21→  onTap,
22→  onRefresh,
23→  language,
24→}) => {
25→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
26→
27→  // Determine state priority: failed > offline+pending > syncing > all synced
28→  const hasFailed = failed > 0;
29→  const isOfflinePending = isOffline && pending > 0;
30→
31→  let bgClass = 'bg-[#4c7c59]/10';
32→  let textClass = 'text-[#4c7c59]';
33→  let label = '';
34→  let icon: React.ReactNode = null;
35→
36→  if (hasFailed) {
37→    bgClass = 'bg-[#c53030]';
38→    textClass = 'text-white';
39→    label = t(`${failed} failed — Tap to view`, `${failed} echecs — Appuyez pour voir`);
40→    icon = <AlertCircle size={12} className="text-white flex-shrink-0" />;
41→  } else if (isOfflinePending) {
42→    bgClass = 'bg-amber-500';
43→    textClass = 'text-white';
44→    label = t(`OFFLINE — ${pending} pending`, `HORS LIGNE — ${pending} en attente`);
45→    icon = <WifiOff size={12} className="text-white flex-shrink-0" />;
46→  } else if (isSyncing) {
47→    bgClass = 'bg-[#0f2b46]';
48→    textClass = 'text-white';
49→    label = t('Syncing...', 'Synchronisation...');
50→    icon = <RefreshCw size={12} className="text-white animate-spin flex-shrink-0" />;
51→  } else {
52→    // All synced
53→    label = t(`${synced} synced`, `${synced} synchronises`);
54→    icon = <CheckCircle size={12} className="text-[#4c7c59] flex-shrink-0" />;
55→  }
56→
57→  return (
58→    <div
59→      className={`sticky top-0 z-30 h-7 flex items-center justify-between px-3 ${bgClass} transition-colors duration-300`}
60→    >
61→      <button
62→        type="button"
63→        onClick={onTap}
64→        className="flex items-center gap-1.5 min-w-0 flex-1"
65→      >
66→        {icon}
67→        <span className={`text-[10px] font-bold uppercase tracking-widest truncate ${textClass}`}>
68→          {label}
69→        </span>
70→      </button>
71→
72→      {onRefresh && !isSyncing && (
73→        <button
74→          type="button"
75→          onClick={(e) => {
76→            e.stopPropagation();
77→            onRefresh();
78→          }}
79→          className={`flex-shrink-0 ml-2 p-0.5 rounded hover:opacity-70 transition-opacity ${textClass}`}
80→          aria-label={t('Refresh', 'Actualiser')}
81→        >
82→          <RefreshCw size={12} />
83→        </button>
84→      )}
85→    </div>
86→  );
87→};
88→
89→export default SyncStatusBar;
