  1→import React, { Suspense, useEffect, useMemo, useRef, useState } from 'react';
  2→import { Category, DataPoint } from '../../types';
  3→import type { CollectionAssignment, MapScope, PointEvent, ProjectedPoint, UserRole } from '../../shared/types';
  4→import {
  5→  BONAMOUSSADI_CENTER,
  6→  CAMEROON_CENTER,
  7→  bonamoussadiLeafletBounds,
  8→  cameroonLeafletBounds,
  9→  isWithinBonamoussadi
 10→} from '../../shared/geofence';
 11→import {
 12→  ChevronDown,
 13→  List,
 14→  Map as MapIcon,
 15→  MapPin,
 16→  Plus,
 17→  ShieldCheck,
 18→  User
 19→} from 'lucide-react';
 20→import VerticalIcon from '../shared/VerticalIcon';
 21→import { categoryLabel as getCategoryLabel, LEGACY_CATEGORY_MAP, VERTICALS } from '../../shared/verticals';
 22→import { apiJson } from '../../lib/client/api';
 23→import { detectLowEndDevice } from '../../lib/client/deviceProfile';
 24→import { getSession } from '../../lib/client/auth';
 25→import BrandLogo from '../BrandLogo';
 26→import DailyProgressWidget from '../DailyProgressWidget';
 27→import StreakTracker from '../StreakTracker';
 28→
 29→interface Props {
 30→  onSelectPoint: (point: DataPoint) => void;
 31→  isAuthenticated: boolean;
 32→  isAdmin?: boolean;
 33→  userRole?: UserRole;
 34→  onAuth: () => void;
 35→  onContribute?: (options?: { batch?: boolean; assignment?: CollectionAssignment | null }) => void;
 36→  onProfile: () => void;
 37→  language: 'en' | 'fr';
 38→}
 39→
 40→type MapPointGroup = {
 41→  key: string;
 42→  latitude: number;
 43→  longitude: number;
 44→  points: DataPoint[];
 45→};
 46→
 47→const HomeMap = React.lazy(() => import('./HomeMap'));
 48→
 49→const BONAMOUSSADI_MAP_BOUNDS = bonamoussadiLeafletBounds();
 50→const CAMEROON_MAP_BOUNDS = cameroonLeafletBounds();
 51→
 52→const normalizeMapScope = (scope: unknown, isAdminMode: boolean): MapScope => {
 53→  if (isAdminMode) return 'global';
 54→  if (scope === 'cameroon' || scope === 'global') return scope;
 55→  return 'bonamoussadi';
 56→};
 57→
 58→const categoryFromSubmission = (category: ProjectedPoint['category']): Category => {
 59→  if (category === 'pharmacy') return Category.PHARMACY;
 60→  if (category === 'fuel_station') return Category.FUEL;
 61→  if (category === 'mobile_money') return Category.MOBILE_MONEY;
 62→  if (category === 'alcohol_outlet') return Category.ALCOHOL_OUTLET;
 63→  if (category === 'billboard') return Category.BILLBOARD;
 64→  if (category === 'transport_road') return Category.TRANSPORT_ROAD;
 65→  if (category === 'census_proxy') return Category.CENSUS_PROXY;
 66→  return Category.PHARMACY;
 67→};
 68→
 69→const selectableCategories: Category[] = [
 70→  Category.PHARMACY,
 71→  Category.FUEL,
 72→  Category.MOBILE_MONEY,
 73→  Category.ALCOHOL_OUTLET,
 74→  Category.BILLBOARD,
 75→  Category.TRANSPORT_ROAD,
 76→  Category.CENSUS_PROXY,
 77→];
 78→
 79→
 80→const Home: React.FC<Props> = ({ onSelectPoint, isAuthenticated, isAdmin, userRole = 'agent', onAuth, onContribute, onProfile, language }) => {
 81→  const [deviceRuntime] = useState(() => ({ lowEnd: detectLowEndDevice() }));
 82→  const [viewMode, setViewMode] = useState<'map' | 'list'>(() => (deviceRuntime.lowEnd ? 'list' : 'map'));
 83→  const [activeCategory, setActiveCategory] = useState<Category>(Category.PHARMACY);
 84→  const [isVerticalPickerOpen, setIsVerticalPickerOpen] = useState(false);
 85→  const [points, setPoints] = useState<DataPoint[]>([]);
 86→  const [isLoadingPoints, setIsLoadingPoints] = useState(true);
 87→  const [assignments, setAssignments] = useState<CollectionAssignment[]>([]);
 88→  const [agentEvents, setAgentEvents] = useState<PointEvent[]>([]);
 89→  const [mapScope, setMapScope] = useState<MapScope>(() => (isAdmin ? 'global' : 'bonamoussadi'));
 90→  const contributePressTimer = useRef<number | null>(null);
 91→  const longPressTriggered = useRef(false);
 92→  const isLowEndDevice = deviceRuntime.lowEnd;
 93→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 94→
 95→  const selectedCityLabel =
 96→    mapScope === 'cameroon'
 97→      ? t('Cameroon', 'Cameroun')
 98→      : mapScope === 'global'
 99→        ? t('Worldwide', 'Monde entier')
100→        : t('Bonamoussadi, Douala, Cameroon', 'Bonamoussadi, Douala, Cameroun');
101→
102→  const mapCenter: [number, number] =
103→    mapScope === 'cameroon'
104→      ? [CAMEROON_CENTER.latitude, CAMEROON_CENTER.longitude]
105→      : mapScope === 'global'
106→        ? [20, 0]
107→        : [BONAMOUSSADI_CENTER.latitude, BONAMOUSSADI_CENTER.longitude];
108→  const mapZoom = mapScope === 'cameroon' ? 6 : mapScope === 'global' ? 2 : 15;
109→  const mapMinZoom = mapScope === 'cameroon' ? 5 : mapScope === 'global' ? 2 : 14;
110→  const mapBounds =
111→    mapScope === 'bonamoussadi' ? BONAMOUSSADI_MAP_BOUNDS : mapScope === 'cameroon' ? CAMEROON_MAP_BOUNDS : undefined;
112→  const mapLockLabel =
113→    mapScope === 'bonamoussadi'
114→      ? t('GPS Locked', 'GPS verrouille')
115→      : t('GPS Unlocked (Admin)', 'GPS debloque (admin)');
116→
117→  const formatTimeAgo = (iso: string) => {
118→    const created = new Date(iso).getTime();
119→    if (Number.isNaN(created)) return t('Unknown', 'Inconnu');
120→    const diffMs = Date.now() - created;
121→    const minutes = Math.max(1, Math.round(diffMs / 60000));
122→    if (minutes < 60) return language === 'fr' ? `il y a ${minutes} min` : `${minutes} mins ago`;
123→    const hours = Math.round(minutes / 60);
124→    if (hours < 24) return language === 'fr' ? `il y a ${hours}h` : `${hours}h ago`;
125→    const days = Math.round(hours / 24);
126→    return language === 'fr' ? `il y a ${days}j` : `${days}d ago`;
127→  };
128→
129→  const inferAvailability = (category: ProjectedPoint['category'], details: Record<string, unknown>): 'High' | 'Low' | 'Out' => {
130→    if (category === 'pharmacy') {
131→      if (typeof details.isOpenNow === 'boolean') return details.isOpenNow ? 'High' : 'Out';
132→      return 'Low';
133→    }
134→    if (category === 'fuel_station') {
135→      if (typeof details.hasFuelAvailable === 'boolean') return details.hasFuelAvailable ? 'High' : 'Out';
136→      return 'Low';
137→    }
138→    const hasMin50000XafAvailable =
139→      typeof details.hasMin50000XafAvailable === 'boolean'
140→        ? details.hasMin50000XafAvailable
141→        : typeof details.hasCashAvailable === 'boolean'
142→          ? details.hasCashAvailable
143→          : undefined;
144→    if (typeof hasMin50000XafAvailable === 'boolean') return hasMin50000XafAvailable ? 'High' : 'Out';
145→    return 'Low';
146→  };
147→
148→  const mapProjectedToPoint = (point: ProjectedPoint): DataPoint => {
149→    const details = (point.details ?? {}) as Record<string, unknown>;
150→    const type = categoryFromSubmission(point.category);
151→    const name =
152→      (typeof details.name === 'string' && details.name) ||
153→      (typeof details.siteName === 'string' && details.siteName) ||
154→      getCategoryLabel(point.category, language);
155→    const pricesByFuel =
156→      details.pricesByFuel && typeof details.pricesByFuel === 'object'
157→        ? (details.pricesByFuel as Record<string, number>)
158→        : undefined;
159→    const derivedPrice =
160→      typeof details.fuelPrice === 'number'
161→        ? details.fuelPrice
162→        : typeof details.price === 'number'
163→          ? details.price
164→          : pricesByFuel
165→            ? Object.values(pricesByFuel).find((value) => Number.isFinite(value))
166→            : undefined;
167→    const providers = Array.isArray(details.providers)
168→      ? (details.providers as string[]).filter((value) => typeof value === 'string' && value.trim().length > 0)
169→      : [];
170→    const paymentMethods = Array.isArray(details.paymentMethods)
171→      ? (details.paymentMethods as string[])
172→      : Array.isArray(details.paymentModes)
173→        ? (details.paymentModes as string[])
174→        : undefined;
175→    const provider = typeof details.provider === 'string' && details.provider.trim() ? details.provider.trim() : providers[0];
176→    const operator =
177→      (typeof details.operator === 'string' && details.operator.trim()) ||
178→      provider ||
179→      (providers.length > 0 ? providers[0] : undefined);
180→
181→    return {
182→      id: point.pointId,
183→      name,
184→      type,
185→      location: `GPS: ${point.location.latitude.toFixed(4)}°, ${point.location.longitude.toFixed(4)}°`,
186→      coordinates: { latitude: point.location.latitude, longitude: point.location.longitude },
187→      price: typeof derivedPrice === 'number' ? derivedPrice : undefined,
188→      fuelType:
189→        (typeof details.fuelType === 'string' && details.fuelType) ||
190→        (Array.isArray(details.fuelTypes) ? String(details.fuelTypes[0] ?? '') : undefined),
191→      fuelTypes: Array.isArray(details.fuelTypes) ? (details.fuelTypes as string[]) : undefined,
192→      pricesByFuel: pricesByFuel,
193→      quality: typeof details.quality === 'string' ? details.quality : undefined,
194→      currency: 'XAF',
195→      lastUpdated: formatTimeAgo(point.updatedAt),
196→      availability: inferAvailability(point.category, details),
197→      queueLength: typeof details.queueLength === 'string' ? details.queueLength : undefined,
198→      trustScore: 85,
199→      contributorTrust: 'Silver',
200→      provider,
201→      providers,
202→      operator,
203→      merchantId: typeof details.merchantId === 'string' ? details.merchantId : undefined,
204→      hasMin50000XafAvailable:
205→        typeof details.hasMin50000XafAvailable === 'boolean'
206→          ? details.hasMin50000XafAvailable
207→          : typeof details.hasCashAvailable === 'boolean'
208→            ? details.hasCashAvailable
209→            : undefined,
210→      hasCashAvailable:
211→        typeof details.hasCashAvailable === 'boolean'
212→          ? details.hasCashAvailable
213→          : typeof details.hasMin50000XafAvailable === 'boolean'
214→            ? details.hasMin50000XafAvailable
215→            : undefined,
216→      hasFuelAvailable: typeof details.hasFuelAvailable === 'boolean' ? details.hasFuelAvailable : undefined,
217→      openingHours: typeof details.openingHours === 'string' ? details.openingHours : undefined,
218→      isOpenNow: typeof details.isOpenNow === 'boolean' ? details.isOpenNow : undefined,
219→      isOnDuty: typeof details.isOnDuty === 'boolean' ? details.isOnDuty : undefined,
220→      paymentMethods: paymentMethods?.filter((value) => typeof value === 'string' && value.trim().length > 0),
221→      reliability: typeof details.reliability === 'string' ? details.reliability : undefined,
222→      photoUrl: typeof point.photoUrl === 'string' ? point.photoUrl : undefined,
223→      gaps: Array.isArray(point.gaps) ? point.gaps : [],
224→      verified: true
225→    };
226→  };
227→
228→  const formatPaymentMethods = (paymentMethods: string[] | undefined) => {
229→    if (!paymentMethods || paymentMethods.length === 0) {
230→      return t('Accepted payments unavailable', 'Paiements acceptes indisponibles');
231→    }
232→    return paymentMethods.join(', ');
233→  };
234→
235→  const formatExplorerPrimaryMeta = (point: DataPoint) => {
236→    if (point.type === Category.PHARMACY) {
237→      if (typeof point.isOnDuty === 'boolean') {
238→        return point.isOnDuty ? t('Pharmacie de garde', 'Pharmacie de garde') : t('Pas de garde', 'Pas de garde');
239→      }
240→      return t('Statut de garde indisponible', 'Statut de garde indisponible');
241→    }
242→    if (point.type === Category.FUEL) {
243→      return `${t('Paiements', 'Paiements')}: ${formatPaymentMethods(point.paymentMethods)}`;
244→    }
245→    const operator = point.operator || point.provider || point.providers?.[0];
246→    return operator ? `${t('Operateur', 'Operateur')}: ${operator}` : t('Operateur indisponible', 'Operateur indisponible');
247→  };
248→
249→  const formatPharmacyOpenStatus = (point: DataPoint) => {
250→    if (point.type !== Category.PHARMACY) return null;
251→    return point.isOpenNow ? t('Ouvert maintenant', 'Ouvert maintenant') : t('Statut indisponible', 'Statut indisponible');
252→  };
253→
254→  useEffect(() => {
255→    if (!isAuthenticated || !isAdmin) {
256→      setMapScope('bonamoussadi');
257→      return;
258→    }
259→    setMapScope('global');
260→  }, [isAuthenticated, isAdmin]);
261→
262→  useEffect(() => {
263→    const loadPoints = async () => {
264→      try {
265→        setIsLoadingPoints(true);
266→        const params = new URLSearchParams();
267→        if (mapScope !== 'bonamoussadi') params.set('scope', mapScope);
268→        const query = params.toString();
269→        const data = await apiJson<ProjectedPoint[]>(query ? `/api/submissions?${query}` : '/api/submissions');
270→        if (Array.isArray(data)) {
271→          const mapped = data
272→            .map(mapProjectedToPoint)
273→            .filter((point) => (mapScope === 'bonamoussadi' ? isWithinBonamoussadi(point.coordinates) : true));
274→          setPoints(mapped);
275→        }
276→      } catch {
277→        setPoints([]);
278→      } finally {
279→        setIsLoadingPoints(false);
280→      }
281→    };
282→    void loadPoints();
283→  }, [language, mapScope]);
284→
285→  useEffect(() => {
286→    let cancelled = false;
287→    const loadAgentData = async () => {
288→      if (!isAuthenticated || userRole === 'client') {
289→        setAssignments([]);
290→        setAgentEvents([]);
291→        return;
292→      }
293→
294→      try {
295→        const eventsParams = new URLSearchParams({ view: 'events' });
296→        if (isAdmin) eventsParams.set('scope', 'global');
297→        const [session, assignmentData, eventData] = await Promise.all([
298→          getSession(),
299→          apiJson<CollectionAssignment[]>('/api/user?view=assignments'),
300→          apiJson<PointEvent[]>(`/api/submissions?${eventsParams.toString()}`),
301→        ]);
302→        const userId = session?.user?.id?.toLowerCase().trim() ?? '';
303→        if (cancelled) return;
304→        setAssignments(Array.isArray(assignmentData) ? assignmentData : []);
305→        const ownEvents = Array.isArray(eventData)
306→          ? eventData.filter((event) => (typeof event.userId === 'string' ? event.userId.toLowerCase().trim() : '') === userId)
307→          : [];
308→        setAgentEvents(ownEvents);
309→      } catch {
310→        if (cancelled) return;
311→        setAssignments([]);
312→        setAgentEvents([]);
313→      }
314→    };
315→
316→    void loadAgentData();
317→    return () => {
318→      cancelled = true;
319→    };
320→  }, [isAuthenticated, isAdmin, language, userRole]);
321→
322→  useEffect(() => {
323→    return () => {
324→      if (contributePressTimer.current) {
325→        window.clearTimeout(contributePressTimer.current);
326→      }
327→    };
328→  }, []);
329→
330→  const filteredPoints = useMemo(() => points.filter((point) => point.type === activeCategory), [activeCategory, points]);
331→
332→  const mapPointGroups = useMemo<MapPointGroup[]>(() => {
333→    const groups = new Map<string, MapPointGroup>();
334→    for (const point of filteredPoints) {
335→      if (!point.coordinates) continue;
336→      if (mapScope === 'bonamoussadi' && !isWithinBonamoussadi(point.coordinates)) continue;
337→      const latitude = Number(point.coordinates.latitude.toFixed(5));
338→      const longitude = Number(point.coordinates.longitude.toFixed(5));
339→      const key = `${latitude}_${longitude}`;
340→      const existing = groups.get(key);
341→      if (existing) {
342→        existing.points.push(point);
343→      } else {
344→        groups.set(key, { key, latitude, longitude, points: [point] });
345→      }
346→    }
347→    return Array.from(groups.values());
348→  }, [filteredPoints, mapScope]);
349→
350→  const categoryLabel = (type: Category) => {
351→    const verticalId = LEGACY_CATEGORY_MAP[type] ?? type;
352→    return getCategoryLabel(verticalId, language);
353→  };
354→
355→  const showAgentWidgets = isAuthenticated && userRole !== 'client';
356→  const activeAssignment = useMemo(() => {
357→    const active = assignments
358→      .filter((assignment) => assignment.status === 'in_progress' || assignment.status === 'pending')
359→      .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());
360→    return active[0] ?? null;
361→  }, [assignments]);
362→
363→  const todayKey = (() => {
364→    const now = new Date();
365→    const y = now.getFullYear();
366→    const m = String(now.getMonth() + 1).padStart(2, '0');
367→    const d = String(now.getDate()).padStart(2, '0');
368→    return `${y}-${m}-${d}`;
369→  })();
370→  const localDateKey = (iso: string) => {
371→    const date = new Date(iso);
372→    if (Number.isNaN(date.getTime())) return '';
373→    const y = date.getFullYear();
374→    const m = String(date.getMonth() + 1).padStart(2, '0');
375→    const d = String(date.getDate()).padStart(2, '0');
376→    return `${y}-${m}-${d}`;
377→  };
378→  const submissionsToday = agentEvents.filter((event) => localDateKey(event.createdAt) === todayKey).length;
379→  const enrichmentsToday = agentEvents.filter((event) => event.eventType === 'ENRICH_EVENT' && localDateKey(event.createdAt) === todayKey).length;
380→  const averageQuality = (() => {
381→    const todayEvents = agentEvents.filter((event) => localDateKey(event.createdAt) === todayKey);
382→    if (todayEvents.length === 0) return 0;
383→    const total = todayEvents.reduce((sum, event) => {
384→      const details = (event.details ?? {}) as Record<string, unknown>;
385→      const score = typeof details.confidenceScore === 'number' ? details.confidenceScore : 75;
386→      return sum + score;
387→    }, 0);
388→    return Math.round(total / todayEvents.length);
389→  })();
390→  const streakDays = (() => {
391→    if (agentEvents.length === 0) return 0;
392→    const dates = Array.from(new Set(agentEvents.map((event) => localDateKey(event.createdAt)))).sort().reverse();
393→    let streak = 0;
394→    let cursor = new Date();
395→    while (true) {
396→      const key = localDateKey(cursor.toISOString());
397→      if (!dates.includes(key)) break;
398→      streak += 1;
399→      cursor.setDate(cursor.getDate() - 1);
400→    }
401→    return streak;
402→  })();
403→  const streakActiveDays = (() => {
404→    const dateSet = new Set(agentEvents.map((event) => localDateKey(event.createdAt)));
405→    return Array.from({ length: 7 }, (_, index) => {
406→      const date = new Date();
407→      date.setDate(date.getDate() - (6 - index));
408→      return dateSet.has(localDateKey(date.toISOString()));
409→    });
410→  })();
411→  const dailyTarget = activeAssignment?.pointsExpected && activeAssignment.pointsExpected > 0 ? activeAssignment.pointsExpected : 10;
412→
413→  const launchSingleCapture = () => {
414→    if (isAuthenticated && onContribute) {
415→      onContribute({ assignment: activeAssignment });
416→      return;
417→    }
418→    onAuth();
419→  };
420→
421→  const handleContributePressStart = () => {
422→    if (!isAuthenticated || !onContribute) return;
423→    longPressTriggered.current = false;
424→    if (contributePressTimer.current) {
425→      window.clearTimeout(contributePressTimer.current);
426→    }
427→    contributePressTimer.current = window.setTimeout(() => {
428→      longPressTriggered.current = true;
429→      onContribute({ batch: true, assignment: activeAssignment });
430→    }, 550);
431→  };
432→
433→  const handleContributePressEnd = () => {
434→    if (contributePressTimer.current) {
435→      window.clearTimeout(contributePressTimer.current);
436→      contributePressTimer.current = null;
437→    }
438→    if (longPressTriggered.current) {
439→      window.setTimeout(() => {
440→        longPressTriggered.current = false;
441→      }, 0);
442→      return;
443→    }
444→    launchSingleCapture();
445→  };
446→
447→  return (
448→    <div
449→      className="flex h-full min-h-0 flex-col overflow-y-auto bg-[#f9fafb] no-scrollbar"
450→      style={{ WebkitOverflowScrolling: 'touch' }}
