 30→export function computeBadges(events: PointEvent[], language: 'en' | 'fr'): Badge[] {
 31→  const totalSubmissions = events.length;
 32→  const uniqueCategories = new Set(events.map((e) => e.category));
 33→
 34→  const categoryCounts: Record<string, number> = {};
 35→  for (const event of events) {
 36→    categoryCounts[event.category] = (categoryCounts[event.category] ?? 0) + 1;
 37→  }
 38→  const maxInOneVertical = Math.max(0, ...Object.values(categoryCounts));
 39→
 40→  const qualityEvents = events.filter((e) => {
 41→    const details = (e.details ?? {}) as Record<string, unknown>;
 42→    return typeof details.confidenceScore === 'number' && details.confidenceScore > 90;
 43→  });
 44→  let consecutiveHighQuality = 0;
 45→  let maxConsecutiveHighQuality = 0;
 46→  for (const event of events.sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())) {
 47→    const details = (event.details ?? {}) as Record<string, unknown>;
 48→    if (typeof details.confidenceScore === 'number' && details.confidenceScore > 90) {
 49→      consecutiveHighQuality += 1;
 50→      maxConsecutiveHighQuality = Math.max(maxConsecutiveHighQuality, consecutiveHighQuality);
 51→    } else {
 52→      consecutiveHighQuality = 0;
 53→    }
 54→  }
 55→
 56→  const dateDays = new Set(events.map((e) => e.createdAt.slice(0, 10)));
 57→  const sortedDates = Array.from(dateDays).sort().reverse();
 58→  let streakDays = 0;
 59→  const cursor = new Date();
 60→  while (true) {
 61→    const key = cursor.toISOString().slice(0, 10);
 62→    if (!sortedDates.includes(key)) break;
 63→    streakDays += 1;
 64→    cursor.setDate(cursor.getDate() - 1);
 65→  }
 66→
 67→  const eveningEvents = events.filter((e) => {
 68→    const hour = new Date(e.createdAt).getHours();
 69→    return hour >= 18 && e.category === 'alcohol_outlet';
 70→  });
 71→
 72→  const rainySeasonEvents = events.filter((e) => {
 73→    const month = new Date(e.createdAt).getMonth();
 74→    return month >= 5 && month <= 9;
 75→  });
 76→
 77→  return [
 78→    {
 79→      id: 'first_steps',
 80→      labelEn: 'First Steps',
 81→      labelFr: 'Premiers pas',
 82→      descriptionEn: 'Complete your first submission',
 83→      descriptionFr: 'Completez votre premiere soumission',
 84→      icon: Footprints,
 85→      color: '#4c7c59',
 86→      bgColor: '#eaf3ee',
 87→      earned: totalSubmissions >= 1,
 88→      progress: Math.min(totalSubmissions, 1),
 89→      target: 1,
 90→    },
 91→    {
 92→      id: 'explorer',
 93→      labelEn: 'Explorer',
 94→      labelFr: 'Explorateur',
 95→      descriptionEn: 'Submit in 3 different verticals',
 96→      descriptionFr: 'Soumettez dans 3 verticales differentes',
 97→      icon: Compass,
 98→      color: '#0f2b46',
 99→      bgColor: '#e7eef4',
100→      earned: uniqueCategories.size >= 3,
101→      progress: Math.min(uniqueCategories.size, 3),
102→      target: 3,
103→    },
104→    {
105→      id: 'specialist',
106→      labelEn: 'Specialist',
107→      labelFr: 'Specialiste',
108→      descriptionEn: '50 submissions in one vertical',
109→      descriptionFr: '50 soumissions dans une verticale',
110→      icon: Star,
111→      color: '#c86b4a',
112→      bgColor: '#fff8f4',
113→      earned: maxInOneVertical >= 50,
114→      progress: Math.min(maxInOneVertical, 50),
115→      target: 50,
116→    },
117→    {
118→      id: 'quality_star',
119→      labelEn: 'Quality Star',
120→      labelFr: 'Etoile qualite',
121→      descriptionEn: '10 consecutive high-quality submissions',
122→      descriptionFr: '10 soumissions haute qualite consecutives',
123→      icon: Award,
124→      color: '#d69e2e',
125→      bgColor: '#fefcbf',
126→      earned: maxConsecutiveHighQuality >= 10,
127→      progress: Math.min(maxConsecutiveHighQuality, 10),
128→      target: 10,
129→    },
130→    {
131→      id: 'night_owl',
132→      labelEn: 'Night Owl',
133→      labelFr: 'Oiseau de nuit',
134→      descriptionEn: '10 submissions after 6pm (alcohol)',
135→      descriptionFr: '10 soumissions apres 18h (alcool)',
136→      icon: Moon,
137→      color: '#6b46c1',
138→      bgColor: '#f7f4ff',
139→      earned: eveningEvents.length >= 10,
140→      progress: Math.min(eveningEvents.length, 10),
141→      target: 10,
142→    },
143→    {
144→      id: 'rain_walker',
145→      labelEn: 'Rain Walker',
146→      labelFr: 'Marcheur de pluie',
147→      descriptionEn: 'Submit during rainy season (Jun-Oct)',
148→      descriptionFr: 'Soumettez pendant la saison des pluies',
149→      icon: CloudRain,
150→      color: '#2b6cb0',
151→      bgColor: '#ebf4ff',
152→      earned: rainySeasonEvents.length >= 10,
153→      progress: Math.min(rainySeasonEvents.length, 10),
154→      target: 10,
155→    },
156→    {
