 25→function formatStorage(bytes: number, language: 'en' | 'fr'): string {
 26→  if (!Number.isFinite(bytes) || bytes <= 0) return language === 'fr' ? '0 Mo' : '0 MB';
 27→  const mb = bytes / (1024 * 1024);
 28→  return `${mb.toFixed(mb >= 10 ? 0 : 1)} ${language === 'fr' ? 'Mo' : 'MB'}`;
 29→}
