 40→function formatWhen(iso: string, language: 'en' | 'fr'): string {
 41→  const parsed = new Date(iso);
 42→  if (Number.isNaN(parsed.getTime())) return language === 'fr' ? 'Date inconnue' : 'Unknown date';
 43→  return parsed.toLocaleString(language === 'fr' ? 'fr-FR' : 'en-US', {
 44→    month: 'short',
 45→    day: 'numeric',
 46→    hour: '2-digit',
 47→    minute: '2-digit',
 48→  });
