  7→type AggregateRow = {
  8→  userId: string;
  9→  xp: number;
 10→  contributions: number;
 11→  qualityScoreTotal: number;
 12→  lastContributionAt: string | null;
 13→  lastLocation: string;
 14→  verticalBreakdown: Partial<Record<SubmissionCategory, number>>;
 15→};
 16→
 17→const FALLBACK_QUALITY_SCORE = 50;
 18→const LEADERBOARD_CACHE_CONTROL = "public, s-maxage=30, stale-while-revalidate=300";
 19→
 20→function getXpAwarded(submission: PointEvent): number {
 21→  return getEffectiveEventXp(submission);
 22→}
 23→
 24→function getLastLocationLabel(submission: PointEvent): string {
 25→  const details = submission.details as Record<string, unknown> | undefined;
 26→  const siteName = typeof details?.siteName === "string" ? details.siteName.trim() : "";
 27→  if (siteName) return siteName;
 28→  return `GPS ${submission.location.latitude.toFixed(4)}°, ${submission.location.longitude.toFixed(4)}°`;
 29→}
 30→
 31→function getQualityScore(submission: PointEvent): number {
 32→  const details = submission.details as Record<string, unknown> | undefined;
 33→  const rawScore = details?.confidenceScore;
 34→  if (typeof rawScore === "number" && Number.isFinite(rawScore)) {
 35→    return Math.max(0, Math.min(100, Math.round(rawScore)));
 36→  }
 37→  return FALLBACK_QUALITY_SCORE;
 38→}
 39→
 40→function getDisplayName(userId: string, profileName?: string, profileEmail?: string | null, profilePhone?: string | null): string {
 41→  if (profileName && profileName.trim()) return profileName.trim();
 42→  const source =
 43→    profileEmail && profileEmail.trim() ? profileEmail.trim() : profilePhone && profilePhone.trim() ? profilePhone.trim() : userId.trim();
 44→  const atIndex = source.indexOf("@");
 45→  if (atIndex > 0) return source.slice(0, atIndex);
 46→  return source || "Contributor";
 47→}
