 49→export async function GET(): Promise<Response> {
 50→  try {
 51→    const submissions = await buildContributionEvents();
 52→    const rowsByUser = new Map<string, AggregateRow>();
 53→
 54→    for (const submission of submissions) {
 55→      const userId = typeof submission.userId === "string" ? submission.userId.toLowerCase().trim() : "";
 56→      if (!userId) continue;
 57→
 58→      const previous = rowsByUser.get(userId);
 59→      const xpAwarded = getXpAwarded(submission);
 60→      const qualityScore = getQualityScore(submission);
 61→      const createdAt = typeof submission.createdAt === "string" ? submission.createdAt : null;
 62→      const locationLabel = getLastLocationLabel(submission);
 63→
 64→      if (!previous) {
 65→        rowsByUser.set(userId, {
 66→          userId,
 67→          xp: xpAwarded,
 68→          contributions: 1,
 69→          qualityScoreTotal: qualityScore,
 70→          lastContributionAt: createdAt,
 71→          lastLocation: locationLabel,
 72→          verticalBreakdown: {
 73→            [submission.category]: 1,
 74→          },
 75→        });
 76→        continue;
 77→      }
 78→
 79→      previous.xp += xpAwarded;
 80→      previous.contributions += 1;
 81→      previous.qualityScoreTotal += qualityScore;
 82→      previous.verticalBreakdown[submission.category] = (previous.verticalBreakdown[submission.category] ?? 0) + 1;
 83→
 84→      const nextDate = createdAt ? new Date(createdAt).getTime() : Number.NEGATIVE_INFINITY;
 85→      const prevDate = previous.lastContributionAt ? new Date(previous.lastContributionAt).getTime() : Number.NEGATIVE_INFINITY;
 86→      if (nextDate > prevDate) {
 87→        previous.lastContributionAt = createdAt;
 88→        previous.lastLocation = locationLabel;
 89→      }
 90→    }
 91→
 92→    const sorted = [...rowsByUser.values()].sort((a, b) => {
 93→      const bAverageQuality = b.contributions > 0 ? b.qualityScoreTotal / b.contributions : 0;
 94→      const aAverageQuality = a.contributions > 0 ? a.qualityScoreTotal / a.contributions : 0;
 95→      const bRankingScore = Math.round(b.contributions * bAverageQuality);
 96→      const aRankingScore = Math.round(a.contributions * aAverageQuality);
 97→      if (bRankingScore !== aRankingScore) return bRankingScore - aRankingScore;
 98→      if (b.xp !== a.xp) return b.xp - a.xp;
 99→      if (b.contributions !== a.contributions) return b.contributions - a.contributions;
100→      const bTime = b.lastContributionAt ? new Date(b.lastContributionAt).getTime() : 0;
101→      const aTime = a.lastContributionAt ? new Date(a.lastContributionAt).getTime() : 0;
102→      return bTime - aTime;
103→    });
104→
105→    const topRows = sorted.slice(0, 100);
106→    const profileMap = await getUserProfilesBatch(topRows.map((row) => row.userId));
107→
108→    const leaderboard: LeaderboardEntry[] = topRows.map((row, index) => {
109→      const profile = profileMap.get(row.userId);
110→      const averageQualityScore = row.contributions > 0 ? Math.round(row.qualityScoreTotal / row.contributions) : 0;
111→      const rankingScore = Math.round(row.contributions * averageQualityScore);
112→      return {
113→        rank: index + 1,
114→        userId: row.userId,
115→        name: getDisplayName(row.userId, profile?.name, profile?.email, profile?.phone),
116→        xp: row.xp,
117→        contributions: row.contributions,
118→        lastContributionAt: row.lastContributionAt,
119→        lastLocation: row.lastLocation,
120→        averageQualityScore,
121→        rankingScore,
122→        verticalBreakdown: row.verticalBreakdown,
123→      };
124→    });
125→
126→    return jsonResponse(leaderboard, {
127→      status: 200,
128→      headers: {
129→        "cache-control": LEADERBOARD_CACHE_CONTROL,
130→      },
131→    });
132→  } catch (error) {
133→    if (isStorageUnavailableError(error)) {
134→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
135→    }
136→    throw error;
137→  }
138→}
